#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
const int N=200010;
struct nd{int l,r,mx,ad;}tr[N*4];
struct cw{int s,e,m;}f[N];
int k,n,c,ans;
void pu(int p)
{
	tr[p].mx=max(tr[p<<1].mx,tr[p<<1|1].mx);
}
void pd(int p)
{
	if(tr[p].ad)
	{
		tr[p<<1].mx+=tr[p].ad;
		tr[p<<1|1].mx+=tr[p].ad;
		tr[p<<1].ad+=tr[p].ad;
		tr[p<<1|1].ad+=tr[p].ad;
		tr[p].ad=0;
	}
}
void bd(int p,int l,int r)
{
	tr[p]={l,r};
	if(l==r)return;
	int m=l+r>>1;
	bd(p<<1,l,m);
	bd(p<<1|1,m+1,r);
	pu(p);
}
void up(int p,int x,int y,int z)
{
	if(x<=tr[p].l&&tr[p].r<=y)
	{
		tr[p].mx+=z;
		tr[p].ad+=z;
		return;
	}
	int m=tr[p].l+tr[p].r>>1;
	pd(p);
	if(x<=m)up(p<<1,x,y,z);
	if(y>m)up(p<<1|1,x,y,z);
	pu(p);
}
int qr(int p,int x,int y)
{
	if(x<=tr[p].l&&tr[p].r<=y)return tr[p].mx;
	int m=tr[p].l+tr[p].r>>1;
	int s=0;
	pd(p);
	if(x<=m)s=max(s,qr(p<<1,x,y));
	if(y>m)s=max(s,qr(p<<1|1,x,y));
	return s;
}
bool cp(cw a,cw b)
{
	return a.e<b.e;
}
int qp(int a,int b)
{
	int res=1;
	wh(b)
	{
		if(b&1)res=res*a;
		a=a*a;
		b>>=1;
	}
	return res;
}
signed main()
{
	IOS
	cin>>k>>n>>c;
	FOR(i,1,k)
	{
		cin>>f[i].s>>f[i].e>>f[i].m;
	}
	sort(f+1,f+k+1,cp);
	bd(1,1,n);
	int l=0,r=0,mx=0,t=0;
	FOR(i,1,k)
	{
		l=f[i].s;
		r=f[i].e;
		mx=qr(1,l,r-1);
		t=min(c-mx,f[i].m);
		up(1,l,r-1,t);
		ans+=t;
	}
	cout<<ans;
	return 0;
}
